using System;
using System.Threading.Tasks;
using RetroRoyale.Logic;
using RetroGames.Helpers;

namespace RetroRoyale.Protocol.Messages.Server
{
    public class OwnHomeDataMessage : PiranhaMessage
    {
        public OwnHomeDataMessage(Device device) : base(device)
        {
            Id = 24101;
            Device.State = Enums.State.Home;          
        }

        public override async Task Encode()
        {
            /*await Device.Player.LogicClientHome(Stream);
            await Device.Player.LogicClientAvatar(Stream);*/

            await Stream.WriteHex("");
            await Stream.WriteString("<c4>" + Device.Player.Name + "</c>");
            await Stream.WriteHex("020A");

            await Stream.WriteVInt(Device.Player.Score);

            await Stream.WriteHex("980490260000000000002000000000000813050089F9010501");

            await Stream.WriteVInt(Device.Player.Gold);
            await Stream.WriteHex("0502B0040503000504000505");
            await Stream.WriteVInt(Device.Player.Gold);

            await Stream.WriteHex("");
            await Stream.WriteVInt(Device.Player.Diamonds);
            await Stream.WriteHex("84018B6C09B4AE02018C0E9C0200A806B4057CB6010300000000D68288D603A7C4F6930B98A1D901");
        }
    }
}